import React, { useState } from "react";

// Ícono de persona (SVG)
const UserIcon = () => (
  <svg style={{ width: "40px", height: "40px", fill: "#333" }} viewBox="0 0 24 24">
    <path d="M12 12c2.76 0 5-2.24 5-5S14.76 2 12 2 7 4.24 7 7s2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasena, setContrasena] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!usuario || !contrasena) {
      alert("Por favor, rellena todos los campos");
      return;
    }
    // Llamamos a la función onLogin si está definida
    if (onLogin) {
      onLogin({ usuario, contrasena });
    } else {
      console.log({ usuario, contrasena });
    }
  };

  // Contenedor oscuro que envuelve el recuadro de login, ligeramente mayor que el recuadro
  const estilosFondoOscuro = {
    backgroundColor: "rgba(0,0,0,0.7)", // Fondo oscuro semitransparente
    width: "500px",                    // Ajusta según quieras el ancho total
    margin: "40px auto",              // Centrado horizontalmente en la página
    padding: "30px",
    borderRadius: "10px",
    display: "flex",
    justifyContent: "center",
    position: "relative", // Para colocar el ícono y la X de forma absoluta si se desea
    fontFamily: "'Poppins', sans-serif",
  };

  // Recuadro de login en sí, con fondo beige
  const estilosRecuadro = {
    position: "relative",
    backgroundColor: "rgba(245,245,220,0.95)", // Beige semitransparente
    borderRadius: "15px",
    width: "100%",      // O un ancho fijo si deseas algo más estrecho, ej: "400px"
    padding: "40px 20px 20px 20px",
    textAlign: "center",
    boxShadow: "0 2px 6px rgba(0,0,0,0.3)",
  };

  // Ícono de persona, centrado arriba y sobresaliendo del recuadro
  const estilosIcono = {
    position: "absolute",
    top: "-20px",
    left: "50%",
    transform: "translateX(-50%)",
    backgroundColor: "rgba(245,245,220,0.95)",
    borderRadius: "50%",
    padding: "6px",
    boxShadow: "0 2px 4px rgba(0,0,0,0.2)",
  };

  // Botón "X" para cerrar
  const estilosCerrar = {
    position: "absolute",
    top: "10px",
    right: "10px",
    background: "none",
    border: "none",
    fontSize: "18px",
    cursor: "pointer",
    color: "#333",
  };

  // Título principal
  const estilosTitulo = {
    marginTop: "10px", // Espacio debajo del ícono
    marginBottom: "20px",
    fontSize: "20px",
    fontWeight: "bold",
    color: "#333",
    textTransform: "uppercase",
  };

  // Inputs
  const estilosInput = {
    width: "80%",
    margin: "10px auto",
    padding: "10px",
    fontSize: "15px",
    border: "1px solid #bbb",
    borderRadius: "8px",
    outline: "none",
    textAlign: "center",
    backgroundColor: "#fff",
  };

  // Botón Enviar (sin fondo azul, integrado con el recuadro)
  const estilosBoton = {
    margin: "20px auto 0 auto",
    padding: "8px 20px",
    fontSize: "15px",
    border: "1px solid #333", 
    borderRadius: "8px",
    backgroundColor: "transparent",
    color: "#333",
    cursor: "pointer",
    display: "block",
  };

  return (
    // Contenedor oscuro (fondo) un poco más grande que el recuadro
    <div style={estilosFondoOscuro}>
      {/* Recuadro del login */}
      <div style={estilosRecuadro}>
        {/* Botón "X" para cerrar (si onClose está definido) */}
        {onClose && (
          <button style={estilosCerrar} onClick={onClose}>
            X
          </button>
        )}
        {/* Ícono de persona arriba */}
        <div style={estilosIcono}>
          <UserIcon />
        </div>
        {/* Título */}
        <h2 style={estilosTitulo}>Inicio de Sesión</h2>
        {/* Formulario */}
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Usuario"
            style={estilosInput}
            value={usuario}
            onChange={(e) => setUsuario(e.target.value)}
          />
          <input
            type="password"
            placeholder="Contraseña"
            style={estilosInput}
            value={contrasena}
            onChange={(e) => setContrasena(e.target.value)}
          />
          <button type="submit" style={estilosBoton}>
            Enviar
          </button>
        </form>
      </div>
    </div>
  );
};

export default InicioSesion;
